var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"……귀환 보고.","JPN":"……帰還報告。","ENG":"... I’m back to report, Your Highness.","TWN":"……現況回報。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"허신 카미마엘의 소멸 확인.","JPN":"虚神カミマエルの消滅確認。","ENG":"The Hollow God Khamimael was eliminated.","TWN":"幻神卡米麥爾確定死亡。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"늑대가 신의 혼을 삼켰습니다.","JPN":"狼が神の魂を飲み込みました。","ENG":"The Wolf swallowed its soul.","TWN":"狼吞噬掉神的靈魂。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"훌륭하군. 반역자의 딸이여.","JPN":"見事だ。反逆者の娘よ。","ENG":"You did well, daughter of the traitor.","TWN":"非常出色，逆賊之女。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"내 기대를 뛰어넘는 공적이다.","JPN":"私の期待を上回る功績だった。","ENG":"You exceed my expectations.","TWN":"你的功績遠超過我的期待。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"그렇다면…… 이제 가문의 명예를 회복시켜 주실 수 있으십니까?","JPN":"それでは……これで一族の名誉を回復させていただけますでしょうか。","ENG":"Then... will you clear the name of my family now?","TWN":"那……現在可以幫我恢復家族的榮耀嗎？"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"전하.","JPN":"殿下。","ENG":"Your Highness.","TWN":"殿下？"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"물론이다. 그런 하찮은 소원 따위는 충분히 들어 주고도 남을 만한 공적이야.","JPN":"勿論だ。そんなくだらぬ願いなど十分聞き入れてやれる功績だ。","ENG":"I could. To be honest, your contribution exceeds such a trivial wish.","TWN":"有什麼問題，你立下這麼大的功，幫你完成那點心願算什麼。"},"stage":{"bg":"MIND","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L13_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"그, 그렇다면!","JPN":"そ、それでは！","ENG":"Th-then!","TWN":"那……！"},"stage":{"bg":"MIND","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L15_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"하지만 거절한다.","JPN":"だが、断る。","ENG":"But I refuse.","TWN":"不過我拒絕。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"네……?","JPN":"はい……？","ENG":"Huh?","TWN":"什麼……？"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"어, 어째서!!","JPN":"な、なぜですか！！","ENG":"B-but why?!","TWN":"為什麼！！"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그건 네가 진정으로 원하는 것이 아니기 때문이지.","JPN":"それが貴様の本当の望みではないからだ。","ENG":"Because that’s not your true wish.","TWN":"因為那不是你真正想要的。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"원하는 게 아니라니요? 대체, 무슨 말씀을……!","JPN":"望みではない、と？　いったい、どういう……！","ENG":"What do you mean, Your Highness? I don’t understand!","TWN":"不是我真正想要的？這是什麼意思……！"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"잘 떠올려 보아라.","JPN":"よく思い出してみろ。","ENG":"Think about it.","TWN":"你好好回想一下。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"너를 처형장에서 구해 줬을 때, 나는 분명 네 진정한 소망을 이루어 주겠다고 했다.","JPN":"貴様を処刑場で救ったとき、私は確かに貴様の本当の望みを叶えてやると言った。","ENG":"When I saved you from execution, I promised that I was going to grant you something that you truly wish for.","TWN":"我在刑場救下你的時候曾經說過，會完成你真正的心願。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"하지만 그렇게 숱한 세월이 지났는데도 넌 아직 그게 무엇인지 깨닫지 못한 모양이군.","JPN":"だが、これほど長い歳月が経ったというのに、\\n貴様はまだそれが何なのか気づいていないようだな。","ENG":"But after all these years, you still don’t know what that is.","TWN":"但是在經過那麼漫長的時間後，你似乎依舊不明白。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"그런……. 말도 안되는 말씀을…….","JPN":"そんな……とんでもない話を……","ENG":"But... it doesn’t make sense...","TWN":"那是……什麼意思……"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};